import re, os, glob

def slugify(h):
    h = h.strip().lower()
    # GitHub slugger: strip punctuation except hyphens/spaces/word chars, spaces->hyphens
    h = re.sub(r'[^\w\- ]', '', h, flags=re.UNICODE)
    return h.replace(' ', '-')

def headings(path):
    slugs = []
    seen = {}
    for line in open(path):
        m = re.match(r'^(#{1,6})\s+(.*)', line)
        if m:
            s = slugify(m.group(2))
            if s in seen:
                seen[s] += 1
                s = f"{s}-{seen[s]}"
            else:
                seen[s] = 0
            slugs.append(s)
    return set(slugs)

files_to_check = ['design/roadmap.md', '.the-valley/outcomes/oc-2fbcd7b-roadmap-rederived.md']
errors = []
for f in files_to_check:
    text = open(f).read()
    for m in re.finditer(r'\]\(([^)]+)\)', text):
        target = m.group(1)
        if target.startswith('http'):
            continue
        if '#' in target:
            path, frag = target.split('#', 1)
        else:
            path, frag = target, None
        base = os.path.dirname(f)
        full = os.path.normpath(os.path.join(base, path)) if path else f
        if not os.path.exists(full):
            errors.append(f"{f}: missing file {target}")
            continue
        if frag and full.endswith('.md'):
            if frag not in headings(full):
                errors.append(f"{f}: missing anchor #{frag} in {full}")

# inbound links into roadmap.md anchors from the rest of the repo
road = headings('design/roadmap.md')
for f in glob.glob('**/*.md', recursive=True):
    text = open(f).read()
    for m in re.finditer(r'\]\(([^)]*roadmap\.md)#([^)]+)\)', text):
        if m.group(2) not in road:
            errors.append(f"INBOUND {f}: missing roadmap anchor #{m.group(2)}")

print('\n'.join(errors) if errors else 'ALL LINKS OK')
print('roadmap anchors:', sorted(road))
EOF
